const now = new Date(); // Assume this is Friday, April 3
const dayOfWeek = now.getDay(); // This will be 5 (Friday)

// Calculate the distance to Monday (Monday is 1)
const distanceToMonday = dayOfWeek - 1; // 5 - 1 = 4 days

const thisMonday = new Date(now);
thisMonday.setDate(now.getDate() - distanceToMonday); // 3rd minus 4 = March 30
thisMonday.setHours(0, 0, 0, 0);

const todayEnd = new Date(now);
todayEnd.setHours(23, 59, 59, 999); // April 3, 23:59

return items.filter(item => {
  const d = new Date(item.json.Date);
  return d >= thisMonday && d <= todayEnd;
});

// Monthly Logic: Filter for the current month
const now = new Date();
const currentMonth = now.getMonth();
const currentYear = now.getFullYear();

const filtered = items.filter(item => {
  const d = new Date(item.json.Date);
  return d.getMonth() === currentMonth && d.getFullYear() === currentYear;
});

return filtered;

// Get current UTC time and convert to Philippine Time (+8 hours)

const now = new Date();
const phtTime = new Date(now.getTime() + (8 * 60 * 60 * 1000));

const day = phtTime.getUTCDay();   // 0=Sun, 1=Mon, ..., 5=Fri
const hour = phtTime.getUTCHours(); 
const date = phtTime.getUTCDate();

//Last day of month
const lastDayOfMonth = new Date(phtTime.getUTCFullYear(), phtTime.getUTCMonth() + 1, 0).getDate();

let reportModes = [];

// 1. DAILY: Mon-Fri at 5 PM (17:00)
if (day >= 1 && day <= 5 && hour === 17) {
  reportModes.push("Daily");
}

// 2. WEEKLY: Friday at 5 PM (17:00)
if (day === 5 && hour === 17) {
  reportModes.push("Weekly");
}

// 3. MONTHLY: Last day of Month at 5PM
if (date === lastDayOfMonth && hour === 17) {
  reportModes.push("Monthly");
}

return reportModes.flatMap(mode => {
  return items.map(item => ({
    json: {
      ...item.json,
      reportMode: mode 
    }
  }));
});

// 1. Check if we have data
if (items.length === 0) {
  return [{
    json: {
      reportType: "No Data",
      dateRange: "N/A",
      totals: { Leads: 0, Calls: 0, Appointments: 0, Sales: 0, Revenue: 0 },
      rows: []
    }
  }];
}

// 2. Identify the report type and prepare date range
const reportType = items[0].json.reportMode || 'Sales';
let totals = { Leads: 0, Calls: 0, Appointments: 0, Sales: 0, Revenue: 0 };
let dateRange = "";

const now = new Date();
const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

// 3. Generate Date Label based on your NEW Friday-to-Friday filter logic
if (reportType === "Daily") {
    dateRange = now.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
} else if (reportType === "Weekly") {
    // Today is Friday (April 3), so we go back 4 days to get Monday (March 30)
    const thisMonday = new Date(now);
    thisMonday.setDate(now.getDate() - 4);

    // Friday is Today (April 3)
    const thisFriday = new Date(now);

    dateRange = `${monthNames[thisMonday.getMonth()]} ${thisMonday.getDate()} - ${monthNames[thisFriday.getMonth()]} ${thisFriday.getDate()}, ${thisFriday.getFullYear()}`;
} else if (reportType === "Monthly") {
    dateRange = `${monthNames[now.getMonth()]} ${now.getFullYear()}`;
}


// 4. Clean the rows and sum up the totals
const cleanRows = items.map(item => {
  const row = { ...item.json };

  // Remove the routing column so it doesn't show in the table
  delete row.reportMode;
  delete row.signatureBase64;

  // Sum totals
  totals.Leads += Number(row.Leads || 0);
  totals.Calls += Number(row.Calls || 0);
  totals.Appointments += Number(row.Appointments || 0);
  totals.Sales += Number(row.Sales || 0);
  totals.Revenue += Number(row.Revenue || 0);

  return row;
});

// To access the signature from the Merge node's second input (index 1)
const signatureData = $('JsonSign').first().json.signatureBase64 || "";
// 5. Pass everything to the HTML // 5. Final Return (The Fixed Block)
return [{
  json: {
    reportType: reportType,
    dateRange: dateRange,
    totals: totals,
    rows: cleanRows,
    signatures: [
      {
        salesName: "John Smith",
        signature: `data:image/png;base64,${signatureData}`
      }
    ]
  }
}];

const { reportType, totals, rows, dateRange, signatures } = items[0].json;

// Get the specific signature data from the first object in the array
