const salesName = signatures[0].salesName;


// 1. Map the clean rows into HTML <tr> strings
const rowsHtml = rows.map(row => `
  <tr>
    <td>${row.Date || '-'}</td>
    <td>${row.Leads || 0}</td>
    <td>${row.Calls || 0}</td>
    <td>${row.Appointments || 0}</td>
    <td>${row.Sales || 0}</td>
    <td>${Number(row.Revenue || 0).toLocaleString()}</td>
  </tr>
`).join('');

// 2. Create the bold total row
const totalRowHtml = `
  <tr style="font-weight:bold; background:#f2f2f2;">
